import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const x=JSON.parse('{"title":"界域概要","description":"","frontmatter":{},"headers":[],"relativePath":"ja/realms/index.md","filePath":"ja/realms/index.md","lastUpdated":1775394001000}'),n={name:"ja/realms/index.md"};function i(s,t,d,o,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="界域概要" tabindex="-1">界域概要 <a class="header-anchor" href="#界域概要" aria-label="Permalink to &quot;界域概要&quot;">​</a></h1><p><strong>界域</strong>は忘却前夜の世界観とゲームシステムの根幹を成す4つの力の源泉です。すべての覚醒体・カード・装備はいずれかの界域に属し、界域ごとに異なる戦闘スタイルとシナジー効果を持ちます。</p><h2 id="_4つの界域" tabindex="-1">4つの界域 <a class="header-anchor" href="#_4つの界域" aria-label="Permalink to &quot;4つの界域&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">界域</th><th style="text-align:center;">英名</th><th style="text-align:left;">テーマ</th><th style="text-align:left;">戦闘スタイル</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-chaos">混沌</span></td><td style="text-align:center;">Chaos</td><td style="text-align:left;">狂気・混乱・外なる神</td><td style="text-align:left;">狂気バーストによる瞬間火力</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:center;">Aequor</td><td style="text-align:left;">深淵・海洋・インスマス</td><td style="text-align:left;">防御・回復・コントロール</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:center;">Caro</td><td style="text-align:left;">変容・肉体・シュブ＝ニグラス</td><td style="text-align:left;">自傷ギミック・高HP戦略</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:center;">Ultra</td><td style="text-align:left;">次元・超越・ヨグ＝ソトース</td><td style="text-align:left;">算力操作・ドロー加速</td></tr></tbody></table><h2 id="界域の影響範囲" tabindex="-1">界域の影響範囲 <a class="header-anchor" href="#界域の影響範囲" aria-label="Permalink to &quot;界域の影響範囲&quot;">​</a></h2><p>界域は以下のゲーム要素に関わります。</p><ul><li><strong>覚醒体</strong> — 各覚醒体は1つの界域に属する</li><li><strong>カード</strong> — カードの効果は界域の特性を反映</li><li><strong>界域シナジー</strong> — 編成内の同界域覚醒体数でボーナスが発動</li><li><strong>相性</strong> — 一部コンテンツで界域間の有利不利が存在</li><li><strong>装備（運命の輪・密契）</strong> — 界域限定の装備が存在</li></ul><h2 id="界域シナジー早見表" tabindex="-1">界域シナジー早見表 <a class="header-anchor" href="#界域シナジー早見表" aria-label="Permalink to &quot;界域シナジー早見表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">同界域数</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:center;">2体</td><td style="text-align:left;">基本シナジー発動</td></tr><tr><td style="text-align:center;">3体</td><td style="text-align:left;">強化シナジー発動</td></tr><tr><td style="text-align:center;">4体</td><td style="text-align:left;">最大シナジー発動（単色ボーナス）</td></tr></tbody></table><p>詳細は<a href="./../awakeners/team-building.html">編成ガイド</a>をご覧ください。</p><h2 id="各界域の詳細" tabindex="-1">各界域の詳細 <a class="header-anchor" href="#各界域の詳細" aria-label="Permalink to &quot;各界域の詳細&quot;">​</a></h2><ul><li><a href="./chaos.html">混沌（Chaos）</a></li><li><a href="./aequor.html">深海（Aequor）</a></li><li><a href="./caro.html">血肉（Caro）</a></li><li><a href="./ultra.html">超維（Ultra）</a></li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../awakeners/">覚醒体図鑑</a></li><li><a href="./../cards/">カードシステム概要</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',14)])])}const f=e(n,[["render",i]]);export{x as __pageData,f as default};
